+Instruction *InstCombinerImpl::foldSelectWithBoolCond(SelectInst &SI) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Match outer select with condition being a boolean select:
+  //   select (select C, X, BoolConst), T, F
+  // Also handle the case where the condition is the NOT of a boolean select:
+  //   select (not (select C, X, BoolConst)), T, F
+  bool IsOuterCondInverted = false;
+  auto *CondSel = dyn_cast<SelectInst>(CondVal);
+  if (!CondSel || !CondSel->getType()->isIntOrIntVectorTy(1)) {
+    // Check if the condition is the NOT of a boolean select
+    Value *NotCondSel;
+    if (match(CondVal, m_Not(m_Value(NotCondSel)))) {
+      CondSel = dyn_cast<SelectInst>(NotCondSel);
+      if (!CondSel || !CondSel->getType()->isIntOrIntVectorTy(1))
+        return nullptr;
+      IsOuterCondInverted = true;
+    } else
+      return nullptr;
+  }
+
+  Value *C = CondSel->getCondition();
+  Value *X = CondSel->getTrueValue();
+  Value *BoolConst = CondSel->getFalseValue();
+
+  // If the outer condition was inverted, push the NOT into the select:
+  //   not (select C, X, K)  =  select C, (not X), (not K)
+  if (IsOuterCondInverted) {
+    X = Builder.CreateNot(X);
+    BoolConst = Builder.CreateNot(BoolConst);
+    std::swap(TrueVal, FalseVal);
+  }
+
+  // Determine if BoolConst (FalseVal of CondSel) is true or false
+  bool IsBoolTrue, IsConstOnFalseVal;
+  if (match(BoolConst, m_Zero())) {
+    IsBoolTrue = false;
+    IsConstOnFalseVal = true;
+  } else if (match(BoolConst, m_One())) {
+    IsBoolTrue = true;
+    IsConstOnFalseVal = true;
+  } else if (match(X, m_Zero())) {
+    // select C, false, X  ->  the constant is on the true side
+    IsBoolTrue = false;
+    IsConstOnFalseVal = false;
+  } else if (match(X, m_One())) {
+    // select C, true, X  ->  the constant is on the true side
+    IsBoolTrue = true;
+    IsConstOnFalseVal = false;
+  } else
+    return nullptr;
+
+  // If both the condition select (CondSel) and the inner select have
+  // other uses besides the outer select, the transformation would increase
+  // instruction count. Skip in that case.
+  bool CondSelHasExtraUse = !CondSel->hasOneUse();
+  auto HasExtraUse = [&](SelectInst *Sel) {
+    return !Sel->hasOneUse();
+  };
+
+  // If the constant is on the true side, the variable (non-constant) is on the
+  // false side. We swap their roles for the purpose of pattern matching.
+  Value *VarVal = IsConstOnFalseVal ? X : BoolConst;
+
+  // Helper to look through a NOT when matching the inner select's condition.
+  // Returns true if the condition of Sel equals V (possibly through a NOT),
+  // and if through NOT, swaps the select's true/false values.
+  auto MatchInnerCond = [&](SelectInst *Sel, Value *V, Value *&A, Value *&B) {
+    if (Sel->getCondition() == V) {
+      A = Sel->getTrueValue();
+      B = Sel->getFalseValue();
+      return true;
+    }
+    // Check if the condition is the NOT of V
+    Value *NotV;
+    if (match(Sel->getCondition(), m_Not(m_Specific(V)))) {
+      // select (not V), A, B  ==  select V, B, A
+      A = Sel->getFalseValue();
+      B = Sel->getTrueValue();
+      return true;
+    }
+    return false;
+  };
+
+  // Also check if CondSel's condition is inverted relative to the inner
+  // select's condition. This handles case 100 (inv.inner.cond.in.outer.cond).
+  auto MatchInvertedC = [&](SelectInst *Sel) -> bool {
+    Value *NotC;
+    if (match(C, m_Not(m_Value(NotC))) &&
+        Sel->getCondition() == NotC) {
+      // CondSel has condition (not C'), inner sel has condition C'.
+      // select (select (not C'), X, K), T, (select C', A, B)
+      // Rewrite as: select (select C', (not K), (not X)), T, (select C', A, B)
+      // But this is equivalent to swapping the arms of CondSel:
+      // select (select C', !K, !X), T, (select C', A, B)
+      // where we also need to adjust X and BoolConst.
+      C = NotC;
+      std::swap(X, BoolConst);
+      X = Builder.CreateNot(X);
+      BoolConst = Builder.CreateNot(BoolConst);
+      // Recompute IsBoolTrue and IsConstOnFalseVal
+      if (match(BoolConst, m_Zero())) {
+        IsBoolTrue = false;
+        IsConstOnFalseVal = true;
+      } else if (match(BoolConst, m_One())) {
+        IsBoolTrue = true;
+        IsConstOnFalseVal = true;
+      } else if (match(X, m_Zero())) {
+        IsBoolTrue = false;
+        IsConstOnFalseVal = false;
+      } else if (match(X, m_One())) {
+        IsBoolTrue = true;
+        IsConstOnFalseVal = false;
+      } else
+        return false;
+      VarVal = IsConstOnFalseVal ? X : BoolConst;
+      return true;
+    }
+    return false;
+  };
+
+  // Check if TrueVal is select C, A, B
+  if (auto *TrueSel = dyn_cast<SelectInst>(TrueVal)) {
+    Value *A, *B;
+    bool Matched = MatchInnerCond(TrueSel, C, A, B);
+    if (!Matched) {
+      Matched = MatchInvertedC(TrueSel);
+      if (Matched)
+        MatchInnerCond(TrueSel, C, A, B);
+    }
+    if (Matched) {
+      if (CondSelHasExtraUse && HasExtraUse(TrueSel))
+        return nullptr;
+      if (IsConstOnFalseVal) {
+        if (IsBoolTrue) {
+          // select (select C, X, true), (select C, A, B), F
+          // -> select C, (select X, A, F), B
+          Value *NewInner = Builder.CreateSelect(X, A, FalseVal);
+          return SelectInst::Create(C, NewInner, B);
+        } else {
+          // select (select C, X, false), (select C, A, B), F
+          // -> select C, (select X, A, F), F
+          Value *NewInner = Builder.CreateSelect(X, A, FalseVal);
+          return SelectInst::Create(C, NewInner, FalseVal);
+        }
+      } else {
+        if (IsBoolTrue) {
+          // select (select C, true, X), (select C, A, B), F
+          // -> select C, A, (select X, B, F)
+          Value *NewInner = Builder.CreateSelect(VarVal, B, FalseVal);
+          return SelectInst::Create(C, A, NewInner);
+        } else {
+          // select (select C, false, X), (select C, A, B), F
+          // -> select C, F, (select X, A, F)
+          Value *NewInner = Builder.CreateSelect(VarVal, A, FalseVal);
+          return SelectInst::Create(C, FalseVal, NewInner);
+        }
+      }
+    }
+  }
+
+  // Check if FalseVal is select C, A, B
+  if (auto *FalseSel = dyn_cast<SelectInst>(FalseVal)) {
+    Value *A, *B;
+    bool Matched = MatchInnerCond(FalseSel, C, A, B);
+    if (!Matched) {
+      Matched = MatchInvertedC(FalseSel);
+      if (Matched)
+        MatchInnerCond(FalseSel, C, A, B);
+    }
+    if (Matched) {
+      if (CondSelHasExtraUse && HasExtraUse(FalseSel))
+        return nullptr;
+      if (IsConstOnFalseVal) {
+        if (IsBoolTrue) {
+          // select (select C, X, true), T, (select C, A, B)
+          // -> select C, (select X, T, A), T
+          Value *NewInner = Builder.CreateSelect(X, TrueVal, A);
+          return SelectInst::Create(C, NewInner, TrueVal);
+        } else {
+          // select (select C, X, false), T, (select C, A, B)
+          // -> select C, (select X, T, A), B
+          Value *NewInner = Builder.CreateSelect(X, TrueVal, A);
+          return SelectInst::Create(C, NewInner, B);
+        }
+      } else {
+        if (IsBoolTrue) {
+          // select (select C, true, X), T, (select C, A, B)
+          // -> select C, T, (select X, T, A)
+          Value *NewInner = Builder.CreateSelect(VarVal, TrueVal, A);
+          return SelectInst::Create(C, TrueVal, NewInner);
+        } else {
+          // select (select C, false, X), T, (select C, A, B)
+          // -> select C, A, (select X, T, B)
+          Value *NewInner = Builder.CreateSelect(VarVal, TrueVal, B);
+          return SelectInst::Create(C, A, NewInner);
+        }
+      }
+    }
+  }
+
+  return nullptr;
+}
+
 Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -2921,6 +3127,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *R = foldSelectOfBools(SI))
     return R;

+  if (Instruction *R = foldSelectWithBoolCond(SI))
+    return R;
