  Value *BoolConst = CondSel->getFalseValue();

  // If the outer condition was inverted, push the NOT into the select:
  //   not (select C, X, K)  =  select C, (not X), (not K)
  if (IsOuterCondInverted) {
    X = Builder.CreateNot(X);
    BoolConst = Builder.CreateNot(BoolConst);
    std::swap(TrueVal, FalseVal);
  }

  // Determine if BoolConst (FalseVal of CondSel) is true or false
  bool IsBoolTrue, IsConstOnFalseVal;
  if (match(BoolConst, m_Zero())) {
    IsBoolTrue = false;
    IsConstOnFalseVal = true;
  } else if (match(BoolConst, m_One())) {
    IsBoolTrue = true;
    IsConstOnFalseVal = true;
  } else if (match(X, m_Zero())) {
    // select C, false, X  ->  the constant is on the true side
    IsBoolTrue = false;
    IsConstOnFalseVal = false;
  } else if (match(X, m_One())) {
    // select C, true, X  ->  the constant is on the true side
    IsBoolTrue = true;
    IsConstOnFalseVal = false;
  } else
    return nullptr;

  // If both the condition select (CondSel) and the inner select have
  // other uses besides the outer select, the transformation would increase
  // instruction count. Skip in that case.
  bool CondSelHasExtraUse = !CondSel->hasOneUse();
  auto HasExtraUse = [&](SelectInst *Sel) {
    return !Sel->hasOneUse();
  };

  // If the constant is on the true side, the variable (non-constant) is on the
  // false side. We swap their roles for the purpose of pattern matching.
  Value *VarVal = IsConstOnFalseVal ? X : BoolConst;

  // Helper to look through a NOT when matching the inner select's condition.
  // Returns true if the condition of Sel equals V (possibly through a NOT),
  // and if through NOT, swaps the select's true/false values.
  auto MatchInnerCond = [&](SelectInst *Sel, Value *V, Value *&A, Value *&B) {
    if (Sel->getCondition() == V) {
      A = Sel->getTrueValue();
      B = Sel->getFalseValue();
      return true;
    }
    // Check if the condition is the NOT of V
    Value *NotV;
    if (match(Sel->getCondition(), m_Not(m_Specific(V)))) {
      // select (not V), A, B  ==  select V, B, A
      A = Sel->getFalseValue();
      B = Sel->getTrueValue();
      return true;
    }
    return false;
  };

  // Also check if CondSel's condition is inverted relative to the inner
  // select's condition. This handles case 100 (inv.inner.cond.in.outer.cond).
  auto MatchInvertedC = [&](SelectInst *Sel) -> bool {
    Value *NotC;
    if (match(C, m_Not(m_Value(NotC))) &&
        Sel->getCondition() == NotC) {
      // CondSel has condition (not C'), inner sel has condition C'.
      // select (select (not C'), X, K), T, (select C', A, B)
      // Rewrite as: select (select C', (not K), (not X)), T, (select C', A, B)
      // But this is equivalent to swapping the arms of CondSel:
      // select (select C', !K, !X), T, (select C', A, B)
      // where we also need to adjust X and BoolConst.
      C = NotC;
      std::swap(X, BoolConst);
      X = Builder.CreateNot(X);
      BoolConst = Builder.CreateNot(BoolConst);
